package platform

import (
	"context"
	"testing"
)

func TestUCApplication(t *testing.T) {
	ext := newUCApplication()
	if ext.Key() != KeyUCApplication {
		t.Errorf("Key() = %q, want %q", ext.Key(), KeyUCApplication)
	}
	if ext.Label() != "UC Application" {
		t.Errorf("Label() = %q, want %q", ext.Label(), "UC Application")
	}

	names, err := ext.Extract(context.Background(), nil)
	if err != nil {
		t.Fatalf("Extract returned error: %v", err)
	}
	if len(names) != 9 {
		t.Fatalf("got %d names, want 9", len(names))
	}

	want := map[string]bool{"UC Berkeley": true, "UCLA": true, "UC Merced": true}
	for _, n := range names {
		if n == "" {
			t.Error("found empty name")
		}
		delete(want, n)
	}
	if len(want) > 0 {
		t.Errorf("missing expected names: %v", want)
	}
}

func TestCalStateApply(t *testing.T) {
	ext := newCalStateApply()
	if ext.Key() != KeyCalStateApply {
		t.Errorf("Key() = %q, want %q", ext.Key(), KeyCalStateApply)
	}
	if ext.Label() != "Cal State Apply" {
		t.Errorf("Label() = %q, want %q", ext.Label(), "Cal State Apply")
	}

	names, err := ext.Extract(context.Background(), nil)
	if err != nil {
		t.Fatalf("Extract returned error: %v", err)
	}
	if len(names) != 23 {
		t.Fatalf("got %d names, want 23", len(names))
	}

	want := map[string]bool{
		"San Jose State University":                              true,
		"California Polytechnic State University-San Luis Obispo": true,
		"California State University Channel Islands":             true,
	}
	for _, n := range names {
		if n == "" {
			t.Error("found empty name")
		}
		delete(want, n)
	}
	if len(want) > 0 {
		t.Errorf("missing expected names: %v", want)
	}
}

func TestFloridaSUS(t *testing.T) {
	ext := newFloridaSUS()
	if ext.Key() != KeyFloridaSUS {
		t.Errorf("Key() = %q, want %q", ext.Key(), KeyFloridaSUS)
	}
	if ext.Label() != "Florida SUS" {
		t.Errorf("Label() = %q, want %q", ext.Label(), "Florida SUS")
	}

	names, err := ext.Extract(context.Background(), nil)
	if err != nil {
		t.Fatalf("Extract returned error: %v", err)
	}
	if len(names) != 12 {
		t.Fatalf("got %d names, want 12", len(names))
	}

	want := map[string]bool{
		"University of Florida": true,
		"Florida State University": true,
		"New College of Florida": true,
	}
	for _, n := range names {
		if n == "" {
			t.Error("found empty name")
		}
		delete(want, n)
	}
	if len(want) > 0 {
		t.Errorf("missing expected names: %v", want)
	}
}

func TestExtractReturnsCopy(t *testing.T) {
	ext := newUCApplication()
	names1, _ := ext.Extract(context.Background(), nil)
	names2, _ := ext.Extract(context.Background(), nil)
	names1[0] = "mutated"
	if names2[0] == "mutated" {
		t.Error("Extract should return a copy, not a shared slice")
	}
}

func TestAllIncludesStaticExtractors(t *testing.T) {
	all := All()
	keys := make(map[string]bool)
	for _, e := range all {
		keys[e.Key()] = true
	}
	for _, want := range []string{KeyUCApplication, KeyCalStateApply, KeyFloridaSUS} {
		if !keys[want] {
			t.Errorf("All() missing extractor with key %q", want)
		}
	}
}

